{
  "version": 3,
  "sources": ["src/app/features/coach/bibliotheque/bibliotheque.component.css"],
  "sourcesContent": [".page{display:flex;flex-direction:column;gap:24px}\r\n.page-header{display:flex;align-items:flex-start;justify-content:space-between;flex-wrap:wrap;gap:12px}\r\n.page-sub{color:var(--text-secondary);margin-top:4px}\r\n.lib-stats{display:flex;gap:12px;flex-wrap:wrap}\r\n.lib-stat{background:white;border:1px solid var(--border);border-radius:var(--radius-md);padding:14px 20px;display:flex;flex-direction:column;gap:4px;min-width:100px}\r\n.lib-stat__val{font-family:'Syne',sans-serif;font-size:22px;font-weight:800}\r\n.lib-stat__label{font-size:11px;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.06em}\r\n.filters{display:flex;flex-direction:column;gap:10px}\r\n.filter-group{display:flex;align-items:center;gap:8px;flex-wrap:wrap}\r\n.filter-label{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);min-width:50px}\r\n.search-box{display:flex;align-items:center;gap:8px;background:white;border:1px solid var(--border);border-radius:var(--radius-md);padding:8px 14px;width:100%;max-width:360px}\r\n.search-box input{border:none;outline:none;background:transparent;font-size:13px;flex:1;color:var(--text-primary)}\r\n.tab{padding:6px 14px;border-radius:var(--radius-sm);font-size:12px;font-weight:600;border:1px solid var(--border);cursor:pointer;background:white;color:var(--text-secondary);transition:all 0.15s}\r\n.tab.active{background:var(--orange);color:white;border-color:var(--orange)}\r\n.res-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:16px}\r\n.res-card{padding:20px;cursor:pointer;transition:all 0.2s;border:1px solid var(--border);border-radius:var(--radius-lg);background:white}\r\n.res-card:hover{transform:translateY(-3px);box-shadow:0 8px 24px rgba(0,0,0,0.1);border-color:var(--orange)}\r\n.res-card__top{display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:12px}\r\n.res-icon{font-size:28px}\r\n.res-badges{display:flex;flex-direction:column;gap:4px;align-items:flex-end}\r\n.res-titre{font-family:'Syne',sans-serif;font-size:15px;font-weight:700;margin-bottom:6px}\r\n.res-desc{font-size:12px;color:var(--text-secondary);line-height:1.55;margin-bottom:10px;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}\r\n.res-meta{display:flex;justify-content:space-between;font-size:11px;color:var(--text-muted);margin-bottom:10px}\r\n.prog-row{display:flex;justify-content:space-between;align-items:center;margin-bottom:4px}\r\n.prog-label{font-size:11px;font-weight:600}\r\n.prog-pct{font-size:11px;font-weight:700;color:var(--orange)}\r\n.res-tags{display:flex;flex-wrap:wrap;gap:4px;margin-top:8px}\r\n.res-tag{padding:2px 8px;background:var(--bg-app);border:1px solid var(--border);border-radius:4px;font-size:10px;font-weight:600;color:var(--text-secondary)}\r\n.res-actions{display:flex;gap:8px;margin-top:12px;padding-top:12px;border-top:1px solid var(--border)}\r\n.empty-state{grid-column:1/-1;text-align:center;padding:60px;color:var(--text-muted)}\r\n.modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:1000;display:flex;align-items:center;justify-content:center;padding:20px}\r\n.modal-box{width:100%;max-width:560px;max-height:90vh;overflow-y:auto;padding:28px}\r\n.modal-header{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:16px}\r\n.modal-header h2{font-family:'Syne',sans-serif;font-size:18px;font-weight:700;margin-top:4px}\r\n.modal-icon{font-size:28px;margin-right:10px}\r\n.modal-close{background:none;border:none;cursor:pointer;font-size:18px;color:var(--text-muted);padding:4px 8px}\r\n.modal-desc{font-size:14px;color:var(--text-secondary);line-height:1.6;margin-bottom:20px}\r\n.modal-meta{display:grid;grid-template-columns:1fr 1fr;gap:10px}\r\n.meta-item{display:flex;flex-direction:column;gap:3px}\r\n.meta-key{font-size:11px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);font-weight:600}\r\n.meta-val{font-size:13px;font-weight:600}\r\n.modal-progress{margin-top:16px;padding-top:16px;border-top:1px solid var(--border)}\r\n.modal-footer{display:flex;gap:8px;margin-top:20px;padding-top:16px;border-top:1px solid var(--border);flex-wrap:wrap}\r\n\r\n/* \u2550\u2550 VIEWER \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\r\n.res-open-hint{display:flex;align-items:center;gap:5px;font-size:10px;color:var(--text-muted);margin-top:10px;padding-top:10px;border-top:1px solid var(--border)}\r\n.viewer-overlay{position:fixed;inset:0;background:rgba(0,0,0,0.85);z-index:2000;display:flex;align-items:center;justify-content:center;padding:16px}\r\n.viewer-box{background:var(--color-background-primary,#fff);border-radius:16px;width:100%;max-width:1100px;max-height:95vh;display:flex;flex-direction:column;overflow:hidden}\r\n.viewer-header{display:flex;align-items:center;justify-content:space-between;padding:14px 20px;border-bottom:1px solid var(--border);flex-shrink:0}\r\n.viewer-title{display:flex;align-items:center;gap:10px;font-family:'Syne',sans-serif;font-size:15px;font-weight:700;overflow:hidden}\r\n.viewer-title span:first-child{font-size:20px;flex-shrink:0}\r\n.viewer-title span:nth-child(2){white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\r\n.viewer-prog-badge{padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700;flex-shrink:0}\r\n.viewer-header-right{display:flex;align-items:center;gap:12px;flex-shrink:0}\r\n.viewer-autosave-info{display:flex;align-items:center;gap:5px;font-size:11px;color:var(--green,#27AE7A);font-weight:600}\r\n.viewer-close{background:none;border:1px solid var(--border);border-radius:8px;cursor:pointer;padding:6px;display:flex;align-items:center;justify-content:center;color:var(--text-secondary);transition:all 0.15s}\r\n.viewer-close:hover{background:var(--bg-app);border-color:var(--text-muted)}\r\n.viewer-prog-bar{height:3px;background:var(--border);flex-shrink:0}\r\n.viewer-prog-fill{height:100%;transition:width 0.5s ease;border-radius:2px}\r\n.viewer-content{flex:1;overflow:hidden;display:flex;flex-direction:column;min-height:0}\r\n.viewer-content--center{align-items:center;justify-content:center;padding:40px}\r\n.viewer-video{width:100%;height:100%;object-fit:contain;background:#000;min-height:0}\r\n.viewer-iframe{flex:1;width:100%;border:none;min-height:500px}\r\n.viewer-img{max-width:100%;max-height:100%;object-fit:contain;border-radius:8px}\r\n.viewer-resume-hint{padding:8px 16px;font-size:12px;color:var(--teal,#2ABFBF);font-weight:600;background:rgba(42,191,191,0.08);text-align:center;flex-shrink:0}\r\n.viewer-download-prompt{text-align:center;display:flex;flex-direction:column;align-items:center;gap:16px}\r\n.viewer-dl-icon{font-size:56px}\r\n.viewer-download-prompt h3{font-family:'Syne',sans-serif;font-size:20px;font-weight:700}\r\n.viewer-download-prompt p{color:var(--text-secondary);font-size:14px}\r\n\r\n.viewer-loading{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:16px;color:var(--text-muted)}\r\n.viewer-spinner{width:36px;height:36px;border:3px solid var(--border);border-top-color:var(--orange);border-radius:50%;animation:spin 0.8s linear infinite}\r\n@keyframes spin{to{transform:rotate(360deg)}}\r\n\r\n/* PDF viewer */\r\n.viewer-content--pdf{flex:1;display:flex;flex-direction:column;overflow:hidden;min-height:0}\r\n.pdf-controls{display:flex;align-items:center;gap:12px;padding:10px 16px;border-bottom:1px solid var(--border);flex-shrink:0;background:var(--bg-app)}\r\n.pdf-nav-btn{width:32px;height:32px;border:1px solid var(--border);border-radius:8px;background:white;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all 0.15s;color:var(--text-secondary)}\r\n.pdf-nav-btn:hover:not(:disabled){background:var(--orange);color:white;border-color:var(--orange)}\r\n.pdf-nav-btn:disabled{opacity:0.35;cursor:not-allowed}\r\n.pdf-page-info{display:flex;align-items:baseline;gap:4px;font-size:13px}\r\n.pdf-page-current{font-weight:800;font-family:'Syne',sans-serif;font-size:16px;color:var(--orange)}\r\n.pdf-page-sep{color:var(--text-muted)}\r\n.pdf-page-total{font-weight:600}\r\n.pdf-page-label{font-size:11px;color:var(--text-muted)}\r\n.pdf-inline-prog{display:flex;align-items:center;gap:8px;margin-left:auto}\r\n.pdf-canvas-wrap{flex:1;overflow:auto;display:flex;justify-content:center;padding:16px;background:#525659}\r\n.pdf-canvas{display:block;box-shadow:0 4px 20px rgba(0,0,0,0.3);border-radius:2px;max-width:100%}\r\n\r\n/* Card download button */\r\n.res-card-actions{display:flex;align-items:center;justify-content:space-between;margin-top:10px;padding-top:10px;border-top:1px solid var(--border)}\r\n.res-open-hint{display:flex;align-items:center;gap:5px;font-size:10px;color:var(--text-muted)}\r\n.download-btn{display:flex;align-items:center;gap:5px;padding:4px 10px;border-radius:6px;font-size:11px;font-weight:600;border:1px solid var(--border);background:white;color:var(--text-secondary);cursor:pointer;transition:all 0.15s}\r\n.download-btn:hover{background:var(--orange);color:white;border-color:var(--orange)}\r\n\r\n/* Viewer download button */\r\n.viewer-dl-btn{display:flex;align-items:center;gap:6px;padding:6px 14px;border:1px solid var(--border);border-radius:8px;background:white;cursor:pointer;font-size:12px;font-weight:600;color:var(--text-secondary);transition:all 0.15s}\r\n.viewer-dl-btn:hover{background:var(--orange);color:white;border-color:var(--orange)}\r\n\r\n/* Folders view */\r\n.view-toggle-row{display:flex;gap:6px;margin-bottom:4px}\r\n.view-toggle-row button{display:flex;align-items:center;gap:6px;padding:6px 14px;border-radius:8px;font-size:12px;font-weight:600;border:1px solid var(--border);cursor:pointer;background:white;color:var(--text-secondary);transition:all 0.15s}\r\n.view-toggle-row button.active{background:var(--orange);color:white;border-color:var(--orange)}\r\n.folders-view{display:flex;flex-direction:column;gap:4px}\r\n.folder-row{display:flex;align-items:center;gap:12px;padding:12px 16px;background:white;border:1px solid var(--border);border-radius:var(--radius-md);cursor:pointer;transition:all 0.15s}\r\n.folder-row:hover{border-color:var(--orange);background:#FFF8F5}\r\n.folder-icon-wrap{color:var(--orange);flex-shrink:0}\r\n.folder-meta{flex:1;display:flex;align-items:center;gap:10px}\r\n.folder-name{font-family:'Syne',sans-serif;font-weight:700;font-size:14px}\r\n.folder-count{font-size:11px;color:var(--text-muted);background:var(--bg-app);border:1px solid var(--border);border-radius:10px;padding:2px 8px}\r\n.folder-chevron{color:var(--text-muted);transition:transform 0.2s;flex-shrink:0}\r\n.folder-chevron.open{transform:rotate(90deg)}\r\n.folder-files{margin-left:20px;border-left:2px solid var(--border);padding-left:10px;display:flex;flex-direction:column;gap:3px;margin-bottom:6px}\r\n.folder-file-row{display:flex;align-items:center;gap:16px;padding:9px 12px;background:white;border:1px solid var(--border);border-radius:var(--radius-sm);cursor:pointer;transition:all 0.15s}\r\n.folder-file-row:hover{border-color:var(--teal);background:#F5FFFD}\r\n.ff-icon{font-size:16px;flex-shrink:0}\r\n.ff-info{flex: 1; \r\n    min-width: 0;\r\n    display: flex;\r\n    align-items: center;\r\n    gap: 12px;}\r\n.ff-name{font-size:13px;font-weight:600;display:block;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;flex:1}\r\n.ff-meta{font-size:11px;color:var(--text-muted)}\r\n.ff-prog{display:flex;align-items:center;gap:6px;flex-shrink:0}\r\n.ff-dl-btn{background:none;border:1px solid var(--border);border-radius:6px;padding:4px 6px;cursor:pointer;color:var(--text-secondary);transition:all 0.15s;flex-shrink:0;display:flex;align-items:center}\r\n.ff-dl-btn:hover{background:var(--orange);color:white;border-color:var(--orange)}\r\n.solo-label{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);padding:8px 4px 4px}\r\n.solo-row{margin-bottom:3px}\r\n/* Style pour la taille du fichier (en gris \u00E0 c\u00F4t\u00E9 du nom) */\r\n.ff-size {\r\n    font-size: 12px;\r\n    color: var(--text-muted);\r\n    min-width: 70px; /* Taille fixe pour l'alignement */\r\n}\r\n\r\n/* Alignement des badges et boutons \u00E0 droite */\r\n.ff-side-actions {\r\n    display: flex;\r\n    align-items: center;\r\n    gap: 15px;\r\n    flex-shrink: 0;\r\n}\r\n\r\n/* Ajustement du bouton de t\u00E9l\u00E9chargement */\r\n.ff-dl-btn {\r\n    background: white;\r\n    border: 1px solid var(--border);\r\n    border-radius: 6px;\r\n    padding: 6px;\r\n    cursor: pointer;\r\n    color: var(--text-secondary);\r\n    transition: all 0.15s;\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n}\r\n\r\n.ff-dl-btn:hover {\r\n    background: var(--orange);\r\n    color: white;\r\n    border-color: var(--orange);\r\n}\r\n"],
